+    fn compute_gc_horizon(&self) -> CommitSeq {
+        lock_unpoisoned(&self.concurrent_registry)
+            .gc_horizon()
+            .unwrap_or_else(|| {
+                CommitSeq::new(self.next_commit_seq.load(AtomicOrdering::Acquire))
