+                pages_pruned: 0,
+                versions_freed: 0,
+                versions_budget_exhausted: false,
+                pages_budget_exhausted: false,
+                queue_remaining: 0,
+                pruned_keys: Vec::new(),
+                pruned_indices: Vec::new(),
+            };
+        }
+
+        let mut gc_todo = self.gc_todo.borrow_mut();
+        self.version_store.gc_tick(&mut gc_todo, horizon)
+    }
